{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT volume",
      "simple": "Choose the CT scan you want to use for bone density optimization.",
      "detailed": "The CT volume provides the bone density data needed to plan optimal screw placement. Select the appropriate CT scan from the list; this will serve as the foundation for all subsequent bone segmentation and reconstruction steps."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create bone segmentation",
      "simple": "Switch to the Segment Editor module and create a new segmentation named 'Bone_Segmentation'.",
      "detailed": "This segmentation will hold the bone mask, which isolates the skeletal structures from the CT data. Creating a dedicated segmentation keeps your bone analysis separate from other data and allows you to apply threshold-based bone extraction."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add bone segment",
      "simple": "Click 'Add' and rename the new segment to 'Bone_Segment'.",
      "detailed": "Adding a segment within the segmentation creates a container for the bone region you will define. Rename it 'Bone_Segment' to clearly identify it; this segment will be used to extract the bone surface needed for screw planning."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold tool",
      "simple": "Click the 'Threshold' tool to open the threshold settings.",
      "detailed": "Thresholding converts CT Hounsfield units into a binary mask, highlighting bone (high density) while excluding soft tissue. This step is essential to automatically outline the bone structure based on density criteria."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set threshold range",
      "simple": "Adjust the threshold slider to set the appropriate range for bone.",
      "detailed": "Set the lower threshold to capture cortical and cancellous bone (typically around 150-300 HU) while excluding air and soft tissue. The correct range ensures that only the skeletal anatomy is segmented, providing a clean starting point for bone surface reconstruction."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply threshold",
      "simple": "Click 'Apply' to run the threshold segmentation.",
      "detailed": "Applying the threshold creates the bone mask based on your chosen range. This mask will be refined in the next steps to remove unwanted islands and produce a clean bone segment."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open Islands tool",
      "simple": "Click the 'Islands' tool.",
      "detailed": "The Islands tool allows you to filter out disconnected fragments from the thresholded mask, keeping only the primary bone volume. This cleans up any small artifacts that may interfere with the 3D reconstruction."
    },
    {
      "step_id": "cb_step_8",
      "title": "Keep largest island",
      "simple": "Select 'Keep largest island' to retain only the main bone structure.",
      "detailed": "Choosing 'Keep largest island' removes small, isolated clusters (e.g. noise or tiny bone fragments) and preserves only the largest contiguous bone mass, which is the relevant anatomy for screw placement planning."
    },
    {
      "step_id": "cb_step_9",
      "title": "Apply islands filter",
      "simple": "Click 'Apply' to filter out the small islands.",
      "detailed": "Applying the island filter finalizes the bone segment by discarding extraneous pieces. The resulting binary mask is now a clean representation of the main bone, ready for 3D surface reconstruction."
    },
    {
      "step_id": "cb_step_10",
      "title": "Select bone segment",
      "simple": "Select the 'Bone_Segment' segment as the input for 3D reconstruction.",
      "detailed": "Choosing the correct segment tells the system which bone mask to use for generating the 3D surface model. This model will serve as the anatomical reference for prosthesis placement and screw trajectory planning."
    },
    {
      "step_id": "cb_step_11",
      "title": "3D reconstruction",
      "simple": "Click '3D Reconstruction' to generate the bone surface model.",
      "detailed": "This step converts the bone segmentation into a 3D mesh surface, creating a visual representation of the patient's bone anatomy. The 3D model is essential for precisely identifying landmarks such as the glenoid cavity and planning surgical entry points."
    },
    {
      "step_id": "cb_step_12",
      "title": "Adjust 3D view",
      "simple": "Rotate and zoom the 3D view to clearly see the glenoid cavity.",
      "detailed": "Positioning the 3D view optimally allows you to accurately target the glenoid – the socket of the shoulder joint where the prosthesis will be centered. A clear view ensures that the fiducial point you place next corresponds to the correct anatomical location."
    },
    {
      "step_id": "cb_step_13",
      "title": "Create point markup",
      "simple": "Switch to the Markups module and create a new point list named 'Prosthesis_center_point'.",
      "detailed": "This point will mark the intended center of the shoulder prosthesis on the glenoid surface. Creating a named fiducial makes it easy to reference later during prosthesis implantation and screw planning."
    },
    {
      "step_id": "cb_step_14",
      "title": "Place fiducial point",
      "simple": "Click on the glenoid cavity surface to place the prosthesis center point.",
      "detailed": "Place a single fiducial point at the anatomical center of the glenoid – the cup-shaped socket of the scapula. This point serves as the anchor for positioning the prosthesis and determines the optimal alignment for screw trajectories."
    },
    {
      "step_id": "cb_step_15",
      "title": "Select planning point",
      "simple": "Select the 'Prosthesis_center_point' fiducial as the planning point.",
      "detailed": "Choosing the fiducial you just placed tells the planning algorithm where to anchor the prosthesis. This step links your anatomical mark to the prosthesis implantation functions."
    },
    {
      "step_id": "cb_step_16",
      "title": "Prosthesis implantation",
      "simple": "Click 'Prosthesis implantation' to position the prosthesis model.",
      "detailed": "The algorithm uses the fiducial point and the 3D bone model to automatically place a virtual prosthesis at the glenoid center. This provides a baseline position that can be fine‑tuned with transform handles if needed."
    },
    {
      "step_id": "cb_step_17",
      "title": "Adjust prosthesis?",
      "simple": "Check the box if you need to adjust the prosthesis position; otherwise proceed to planning.",
      "detailed": "If the automatically placed prosthesis is not perfectly aligned, checking this box enables 3D transform handles so you can translate, rotate, or scale it. Fine‑tuning the prosthesis position ensures it matches the patient's anatomy before final screw planning."
    },
    {
      "step_id": "cb_step_18",
      "title": "Adjust transform handles",
      "simple": "Use the 3D transform handles to adjust the prosthesis position.",
      "detailed": "Drag, rotate, or resize the prosthesis using the interactive handles until it is optimally seated on the glenoid surface. Correct alignment is critical for implant stability and proper screw trajectory planning."
    },
    {
      "step_id": "cb_step_19",
      "title": "Update prosthesis",
      "simple": "Click 'Update Prosthesis' to apply the adjustment.",
      "detailed": "This button finalizes the manual adjustments and recomputes the prosthesis geometry. After updating, the prosthesis remains in its new position for subsequent screw trajectory planning."
    },
    {
      "step_id": "cb_step_20",
      "title": "Plan screw trajectories",
      "simple": "Click 'Plan' to compute screw trajectories.",
      "detailed": "The planning algorithm generates optimal screw trajectories based on the prosthesis position and bone anatomy. These trajectories define the entry points, paths, and lengths for surgical screws, serving as the final blueprint for the procedure."
    },
    {
      "step_id": "cb_step_21",
      "title": "Adjust screw?",
      "simple": "Check the box if you need to adjust the screw trajectory; otherwise you are done.",
      "detailed": "If the planned screw paths need refinement (e.g., to avoid critical structures or improve bone purchase), checking this box allows you to manually drag the endpoints. When satisfied, you can stop; if adjustments are needed, proceed to fine‑tune the paths."
    },
    {
      "step_id": "cb_step_22",
      "title": "Adjust screw endpoints",
      "simple": "Drag the endpoints of the screw paths to fine-tune the trajectory.",
      "detailed": "Adjusting the endpoints lets you modify the screw entry point and depth to achieve better purchase in bone or avoid neurovascular bundles. This manual step tailors the plan to the patient's unique anatomy."
    },
    {
      "step_id": "cb_step_23",
      "title": "Update screw",
      "simple": "Click 'Update screw' to apply the trajectory adjustments.",
      "detailed": "This button finalizes the manual adjustments and updates the screw trajectory parameters. The updated plan is now ready for surgical reference."
    }
  ]
}
